import { useSession } from 'next-auth/react';

function Perfil() {
  const { data: session, status } = useSession();

  if (status === 'loading') return <p>Carregando...</p>;
  if (session) return <p>Olá, {session.user.email}</p>;
  return <p>Deslogado</p>;
}

